import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.stream.JsonReader;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

import java.io.IOException;
import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;
import java.util.Date;

class DefaultDateTypeAdapterTest {

    private DefaultDateTypeAdapter<Date> adapter;
    private DefaultDateTypeAdapter.DateType<Date> dateTypeMock;

    @BeforeEach
    void setUp() {
        dateTypeMock = mock(DefaultDateTypeAdapter.DateType.class);
        adapter = new DefaultDateTypeAdapter<>(dateTypeMock, "yyyy-MM-dd");
    }

    @Test
    void read_shouldReturnNull_whenJsonTokenIsNull() throws IOException {
        JsonReader jsonReader = mock(JsonReader.class);
        when(jsonReader.peek()).thenReturn(JsonToken.NULL);

        when(jsonReader.nextNull()).thenAnswer(invocation -> null);

        Date result = adapter.read(jsonReader);

        verify(jsonReader).peek();
        verify(jsonReader).nextNull();
        assertNull(result);
    }

    @Test
    void read_shouldDeserializeDateAndReturnDeserializedValue() throws IOException, NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        JsonReader jsonReader = mock(JsonReader.class);
        when(jsonReader.peek()).thenReturn(JsonToken.STRING);

        // Prepare a Date instance to be returned by deserializeToDate
        Date dateInstance = new Date();

        // Use reflection to invoke private method deserializeToDate
        Method method = DefaultDateTypeAdapter.class.getDeclaredMethod("deserializeToDate", JsonReader.class);
        method.setAccessible(true);
        // We need to mock deserializeToDate to return our dateInstance
        // But since it is private, we cannot mock it directly.
        // So instead, we create a spy on adapter and stub deserializeToDate.
        DefaultDateTypeAdapter<Date> spyAdapter = Mockito.spy(adapter);
        doReturn(dateInstance).when(spyAdapter).deserializeToDate(jsonReader);

        // Mock dateType.deserialize to return a specific value
        Date deserializedDate = new Date(dateInstance.getTime() + 1000);
        when(dateTypeMock.deserialize(dateInstance)).thenReturn(deserializedDate);

        Date result = spyAdapter.read(jsonReader);

        verify(jsonReader).peek();
        verify(spyAdapter).deserializeToDate(jsonReader);
        verify(dateTypeMock).deserialize(dateInstance);
        assertEquals(deserializedDate, result);
    }
}
